SELECT theme_name, download_count
FROM themes
ORDER BY download_count DESC;

SELECT COUNT(download_id) AS download_count
FROM theme_downloads
WHERE theme_id = 0;

SELECT theme_id, user_id
FROM theme_downloads
WHERE theme_id = 0;

SELECT theme_name
FROM themes
WHERE download_count = (
  SELECT MAX(download_count)
  FROM themes
);
